def execute(ctx):
    # Reconcile metered vs settled energy quantities
    accounts = position_keeping.list_accounts(
        account_type="ENERGY_INVENTORY",
    )

    for account in accounts:
        position_keeping.assert_balance(
            account_id=account.account_id,
            instrument_code="KWH",
        )

    return {"status": "reconciled", "accounts_checked": len(accounts)}
